- Créer la structure du projet.
- Générer les fichiers nécessaires, y compris les templates HTML et les fichiers SCSS/CSS.
- Compiler SCSS en CSS.
- Installer Flask.

Il s'agit d'une solution complète pour créer un projet Flask avec une feuille de style dynamique, le tout de manière autonome et modulable.

Pour rendre le projet plus dynamique en récupérant le nom du site et la liste des pages depuis une base de données, nous devons d'abord configurer une base de données dans le projet Flask, puis adapter le code pour utiliser ces données. Voici comment procéder :

### 1. Ajouter SQLAlchemy pour la gestion de la base de données

Nous allons utiliser SQLAlchemy, une bibliothèque ORM (Object Relational Mapper) pour interagir avec la base de données. Vous pouvez l'installer avec `pip` si ce n'est pas déjà fait.

```bash
pip install Flask-SQLAlchemy
```

### 2. Mettre à jour le script pour inclure la configuration de la base de données et les modèles

Voici la version mise à jour du script Python, intégrant la configuration de la base de données et la récupération du nom du site et des pages depuis celle-ci.

```python
import os
import subprocess
from flask_sqlalchemy import SQLAlchemy

# Variables globales pour personnaliser le projet
BASE_DIR = "my_flask_site"
APP_DIR = os.path.join(BASE_DIR, "app")
STATIC_DIR = os.path.join(BASE_DIR, "static")
TEMPLATES_DIR = os.path.join(BASE_DIR, "templates")
MODULES_DIR = os.path.join(TEMPLATES_DIR, "modules")
CSS_DIR = os.path.join(STATIC_DIR, "css")
SCSS_FILE_NAME = "style.scss"
CSS_FILE_NAME = "style.css"
BASE_COLOR = "#3498db"
SECRET_KEY = "your_secret_key_here"
DB_URI = "sqlite:///site.db"  # Base de données SQLite

def create_directory_structure():
    directories = [
        STATIC_DIR,
        CSS_DIR,
        TEMPLATES_DIR,
        MODULES_DIR,
        APP_DIR,
    ]

    for directory in directories:
        os.makedirs(directory, exist_ok=True)

def create_init_file():
    content = f'''from flask import Flask
from flask_sqlalchemy import SQLAlchemy
from app import routes

app = Flask(__name__)
app.config['SECRET_KEY'] = '{SECRET_KEY}'
app.config['SQLALCHEMY_DATABASE_URI'] = '{DB_URI}'
db = SQLAlchemy(app)

from app import models  # Importer les modèles

if __name__ == '__main__':
    app.run(debug=True)
'''
    with open(os.path.join(APP_DIR, '__init__.py'), 'w') as f:
        f.write(content)

def create_models_file():
    content = '''from app import db

class SiteInfo(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)

class Page(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    slug = db.Column(db.String(100), nullable=False)
'''
    with open(os.path.join(APP_DIR, 'models.py'), 'w') as f:
        f.write(content)

def create_routes_file():
    content = '''from flask import render_template
from app import app, db
from app.models import SiteInfo, Page

@app.route('/')
def home():
    site_info = SiteInfo.query.first()
    pages = Page.query.all()
    return render_template('index.html', title=site_info.name, pages=pages)

@app.route('/<slug>')
def page(slug):
    site_info = SiteInfo.query.first()
    page = Page.query.filter_by(slug=slug).first_or_404()
    return render_template('page.html', title=page.title, page=page, site_name=site_info.name)
'''
    with open(os.path.join(APP_DIR, 'routes.py'), 'w') as f:
        f.write(content)

def create_templates():
    templates = {
        "index.html": '''<!doctype html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>{{ title }}</title>
    <link rel="stylesheet" href="{{ url_for('static', filename='css/style.css') }}">
</head>
<body>
    <h1>{{ title }}</h1>
    <nav>
        <ul>
        {% for page in pages %}
            <li><a href="{{ url_for('page', slug=page.slug) }}">{{ page.title }}</a></li>
        {% endfor %}
        </ul>
    </nav>
</body>
</html>
''',
