    conn = sqlite3.connect('alchimie.db')
    cursor = conn.cursor()

    # Récupérer la liste des pages depuis la base de données
    cursor.execute('''
    SELECT pageTitle, slug 
    FROM WebsitePages
    ''')
    pages = cursor.fetchall()

    # Fermer la connexion à la base de données
    conn.close()

    # Générer le contenu du menu
    menu_content = '''<!-- menu.html -->
<ul>
'''
    for page in pages:
        page_title, page_slug = page
        menu_content += f'    <li><a href="{{{{ url_for(\'page\', path=\'{page_slug}\') }}}}">{page_title}</a></li>\n'

    menu_content += '</ul>'

    # Créer le fichier menu.html
    with open(os.path.join(MENUS_DIR, 'menu.html'), 'w') as f:
        f.write(menu_content)

    print("Menu template 'menu.html' créé avec succès dans le répertoire 'menus'.")




